import type React from "react";

import Separator from "../separator/Separator";
import { cn } from "../utils/cn";

type AppBarProps = {
  title: string;
  subtitle?: string;
  breadcrumbs?: React.ReactNode;
  actions?: React.ReactNode;
  className?: string;
  children?: React.ReactNode;
};

/**
 * Page header bar mirroring ViewWrapper.vue.
 *
 * Layout (from the Vue source):
 * - Outer card: bg #f9fbfd, padding 1rem (mobile) / 1rem 1.5rem 4rem (desktop)
 * - Header row: flex justify-between align-center
 *   - Left: <strong> title (inline) + <span> byLine (ml-3, blue-grey, font-weight-light)
 *   - Right: action buttons (e.g. "New Issue")
 * - Divider (v-divider class="mt-3") below header
 * - Content slot below divider
 */
function AppBar({
  title,
  subtitle,
  breadcrumbs,
  actions,
  className,
  children,
}: AppBarProps) {
  return (
    <div
      data-slot="app-bar"
      className={cn(
        "min-h-screen bg-[#f9fbfd]",
        "p-4 md:px-6 md:pb-16",
        className,
      )}
    >
      {/* Header */}
      <div data-slot="app-bar-header">
        {breadcrumbs && (
          <div data-slot="app-bar-breadcrumbs" className="mb-1">
            {breadcrumbs}
          </div>
        )}
        <div className="flex items-center justify-between">
          <span data-slot="app-bar-content" className="flex items-baseline">
            <h1 className="text-base font-bold leading-tight">{title}</h1>
            {subtitle && (
              <span className="ml-3 font-light text-muted-foreground">
                {subtitle}
              </span>
            )}
          </span>
          {actions && (
            <div
              data-slot="app-bar-actions"
              className="flex items-center gap-2"
            >
              {actions}
            </div>
          )}
        </div>
        {/* Divider -- Vue: v-divider class="mt-3" */}
        <Separator className="mt-3" />
      </div>

      {/* Content area */}
      {children && (
        <div data-slot="app-bar-page-content" className="mt-4">
          {children}
        </div>
      )}
    </div>
  );
}

export { AppBar };
export type { AppBarProps };
